   106→    if (!pipeline) return;
   107→
   108→    // Load all steps for the pipeline, then filter to those after the gate
   109→    const allSteps = await this.db
   110→      .select()
   111→      .from(pipelineSteps)
   112→      .where(
   113→        and(
   114→          eq(pipelineSteps.pipelineId, pipeline.id),
   115→          gt(pipelineSteps.position, execution.currentStepPosition),
   116→        ),
   117→      );
   118→    allSteps.sort((a, b) => a.position - b.position);
   119→
