    89→  async resumeFromGate(executionId: string): Promise<void> {
    90→    const [execution] = await this.db
    91→      .select()
    92→      .from(pipelineExecutions)
    93→      .where(eq(pipelineExecutions.id, executionId))
    94→      .limit(1);
