    62→  /**
    63→   * Unsubscribe all handlers, wait for in-flight executions, close bus.
    64→   */
    65→  async stop(): Promise<void> {
    66→    for (const subId of this.subscriptionIds) {
    67→      this.eventBus.unsubscribe(subId);
    68→    }
    69→    this.subscriptionIds.length = 0;
    70→
    71→    // Wait for all in-flight pipeline executions to settle
    72→    await Promise.allSettled(Array.from(this.inFlightExecutions));
    73→
    74→    await this.eventBus.close();
    75→  }
    76→
    77→  // ----------------------------------------------------------
    78→  // REVIEW GATE RESUME
    79→  // ----------------------------------------------------------
    80→
    81→  /**
    82→   * Resume an execution that was paused at a review gate.
    83→   * Called by DecisionRecorder after all decisions for a gate step are complete
    84→   * and the execution status has been set back to 'running'.
    85→   *
    86→   * Loads the execution and remaining steps (position > gate step position),
    87→   * then runs them sequentially exactly as executePipeline() does.
    88→   */
    89→  async resumeFromGate(executionId: string): Promise<void> {
    90→    const [execution] = await this.db
    91→      .select()
    92→      .from(pipelineExecutions)
    93→      .where(eq(pipelineExecutions.id, executionId))
    94→      .limit(1);
    95→
    96→    if (!execution || execution.status !== 'running') return;
    97→
    98→    const pipeline = (
    99→      await this.db
   100→        .select()
   101→        .from(pipelines)
   102→        .where(eq(pipelines.id, execution.pipelineId))
   103→        .limit(1)
   104→    )[0];
   105→
   106→    if (!pipeline) return;
   107→
   108→    // Load all steps for the pipeline, then filter to those after the gate
   109→    const allSteps = await this.db
   110→      .select()
   111→      .from(pipelineSteps)
   112→      .where(
   113→        and(
   114→          eq(pipelineSteps.pipelineId, pipeline.id),
   115→          gt(pipelineSteps.position, execution.currentStepPosition),
   116→        ),
   117→      );
   118→    allSteps.sort((a, b) => a.position - b.position);
   119→
   120→    if (allSteps.length === 0) {
   121→      // No steps after the gate — mark completed
   122→      await this.db
   123→        .update(pipelineExecutions)
   124→        .set({ status: 'completed', completedAt: new Date() })
   125→        .where(eq(pipelineExecutions.id, executionId));
   126→      return;
   127→    }
   128→
   129→    // Load existing execution step records for remaining positions
   130→    const remainingPositions = allSteps.map((s) => s.position);
   131→    const execStepRecords = await this.db
   132→      .select()
   133→      .from(executionSteps)
   134→      .where(
   135→        and(
   136→          eq(executionSteps.executionId, executionId),
   137→          inArray(executionSteps.position, remainingPositions),
   138→        ),
   139→      );
   140→
   141→    // Map position → execStep id for lookup
   142→    const execStepByPosition = new Map(execStepRecords.map((e) => [e.position, e]));
   143→
   144→    const previousStepOutputs = new Map<number, Record<string, unknown>>();
   145→    let stepsCompleted = execution.stepsCompleted;
   146→
   147→    const executionPromise = (async () => {
   148→      for (const step of allSteps) {
   149→        if (step.stepType === 'review_gate') {
   150→          await this.db
   151→            .update(pipelineExecutions)
   152→            .set({ status: 'paused_at_gate', currentStepPosition: step.position })
   153→            .where(eq(pipelineExecutions.id, executionId));
   154→          return;
   155→        }
   156→
   157→        const execStep = execStepByPosition.get(step.position);
   158→        if (!execStep) continue;
   159→
   160→        const context: import('./step-runner.js').ExecutionContext = {
   161→          tenantId: pipeline.tenantId,
   162→          executionId,
   163→          pipelineId: pipeline.id,
   164→          triggerPayload: execution.triggerEventId
   165→            ? {}
   166→            : {},
   167→          previousStepOutputs,
   168→        };
   169→
   170→        const retryPolicy = (pipeline.retryPolicy as RetryPolicy | null) ?? DEFAULT_RETRY_POLICY;
   171→        const result = await this.stepRunner.runStep(execStep.id, step, context, retryPolicy);
   172→
   173→        if (result.success || result.isNoOp) {
   174→          stepsCompleted++;
   175→          if (result.outputData) {
   176→            previousStepOutputs.set(step.position, result.outputData);
   177→          }
   178→          await this.db
   179→            .update(pipelineExecutions)
   180→            .set({ stepsCompleted, currentStepPosition: step.position })
   181→            .where(eq(pipelineExecutions.id, executionId));
   182→        } else {
   183→          await this.db
   184→            .update(pipelineExecutions)
   185→            .set({
   186→              status: 'paused_on_failure',
   187→              currentStepPosition: step.position,
   188→              errorDetail: result.error ?? { message: 'Step failed' },
   189→            })

