    17→export class StepRegistry implements StepHandlerRegistry {
    18→  private readonly handlers = new Map<StepType, PipelineStepHandler>();
    19→
    20→  register(handler: PipelineStepHandler): void {
    21→    this.handlers.set(handler.stepType, handler);
    22→  }
    23→
    24→  getHandler(stepType: StepType): PipelineStepHandler | undefined {
    25→    return this.handlers.get(stepType);
    26→  }
    27→
    28→  getRegisteredTypes(): StepType[] {
    29→    return Array.from(this.handlers.keys());
    30→  }
    31→
    32→  validateStepConfig(stepType: StepType, config: Record<string, unknown>): string[] {
    33→    const handler = this.handlers.get(stepType);
    34→    if (!handler) {
    35→      return [`No handler registered for step type: ${stepType}`];
    36→    }
    37→    return handler.validateConfig(config);
    38→  }
