    15→import {
    16→  pipelines,
    17→  pipelineSteps,
    18→  pipelineExecutions,
    19→  executionSteps,
    20→  triggerEvents,
    21→} from '../schema.js';
    22→import type { Pipeline, PipelineStep } from '../schema.js';
    23→import type { EventBus, EventEnvelope } from '../event-bus/interface.js';
    24→import type { TriggerRegistry } from '../triggers/registry.js';
    25→import type { TriggerContext, TriggerResult } from '../triggers/interface.js';
    26→import type { StepRunner, ExecutionContext } from './step-runner.js';
    27→import { computeIdempotencyKey } from './idempotency.js';
    28→
    29→// ============================================================
    30→// EXECUTOR
    31→// ============================================================
    32→
    33→export class PipelineExecutor {
    34→  private readonly subscriptionIds: string[] = [];
    35→  private readonly inFlightExecutions = new Set<Promise<void>>();
    36→
    37→  constructor(
    38→    private readonly db: NodePgDatabase,
    39→    private readonly eventBus: EventBus,
    40→    private readonly triggerRegistry: TriggerRegistry,
    41→    private readonly stepRunner: StepRunner,
    42→  ) {}
    43→
    44→  // ----------------------------------------------------------
    45→  // LIFECYCLE
    46→  // ----------------------------------------------------------
    47→
    48→  /**
    49→   * Subscribe to all registered trigger event types.
    50→   */
    51→  start(): void {
    52→    const handlers = this.triggerRegistry.getAll();
    53→    for (const handler of handlers) {
    54→      const subId = this.eventBus.subscribe(
    55→        handler.triggerType,
    56→        (event) => this.processEvent(event),
    57→      );
    58→      this.subscriptionIds.push(subId);
    59→    }
    60→  }
    61→
    62→  /**
    63→   * Unsubscribe all handlers, wait for in-flight executions, close bus.
    64→   */
    65→  async stop(): Promise<void> {
    66→    for (const subId of this.subscriptionIds) {
    67→      this.eventBus.unsubscribe(subId);
    68→    }
    69→    this.subscriptionIds.length = 0;
    70→
    71→    // Wait for all in-flight pipeline executions to settle
    72→    await Promise.allSettled(Array.from(this.inFlightExecutions));
    73→
    74→    await this.eventBus.close();
    75→  }
    76→
    77→  // ----------------------------------------------------------
    78→  // EVENT PROCESSING
    79→  // ----------------------------------------------------------
    80→
    81→  /**
    82→   * Process a single event: match it to pipelines, enforce policies,
    83→   * execute matched pipelines.
    84→   */
    85→  async processEvent(event: EventEnvelope): Promise<void> {
    86→    const handler = this.triggerRegistry.getHandler(event.eventType);
    87→    if (!handler) return;
    88→
    89→    // Persist trigger event record
    90→    const triggerEventId = createId();
    91→    await this.db.insert(triggerEvents).values({
    92→      id: triggerEventId,
    93→      tenantId: event.tenantId,
    94→      eventType: event.eventType,
    95→      payload: event.payload,
    96→      status: 'acknowledged',
    97→      acknowledgedAt: new Date(),
    98→    });
    99→
   100→    // Fetch active pipelines for this tenant
   101→    const activePipelines = await this.db
   102→      .select()
   103→      .from(pipelines)
   104→      .where(
   105→        and(
   106→          eq(pipelines.tenantId, event.tenantId),
   107→          eq(pipelines.status, 'active'),
   108→        ),
   109→      );
   110→
   111→    if (activePipelines.length === 0) {
   112→      await this.db
   113→        .update(triggerEvents)
   114→        .set({ status: 'processed', processedAt: new Date() })
   115→        .where(eq(triggerEvents.id, triggerEventId));
   116→      return;
   117→    }
   118→
   119→    // Fetch steps for all active pipelines
   120→    const pipelineIds = activePipelines.map((p) => p.id);
   121→    const allSteps = await this.db
   122→      .select()
   123→      .from(pipelineSteps)
   124→      .where(inArray(pipelineSteps.pipelineId, pipelineIds));
   125→
   126→    // Build step lookup: pipelineId → sorted steps
   127→    const stepsByPipeline = new Map<string, PipelineStep[]>();
   128→    for (const step of allSteps) {
   129→      const existing = stepsByPipeline.get(step.pipelineId) ?? [];
   130→      existing.push(step);
   131→      stepsByPipeline.set(step.pipelineId, existing);
   132→    }
   133→    for (const steps of stepsByPipeline.values()) {
   134→      steps.sort((a, b) => a.position - b.position);
   135→    }
   136→
   137→    // Build trigger context (bridge EventBus envelope → TriggerContext)
   138→    const chainDepth = typeof event.payload['depth'] === 'number'
   139→      ? (event.payload['depth'] as number)
   140→      : 0;
   141→
   142→    const triggerContext: TriggerContext = {
   143→      event: {
   144→        eventId: event.id,
   145→        tenantId: event.tenantId,
   146→        eventType: event.eventType,
   147→        payload: event.payload,
   148→        timestamp: event.createdAt,
   149→      },
   150→      tenantId: event.tenantId,
   151→      currentDepth: chainDepth,
   152→    };
   153→
   154→    // Match pipelines
   155→    const matches: TriggerResult[] = handler.getMatchingPipelines(
   156→      triggerContext,
   157→      activePipelines,
   158→    );
   159→
   160→    // Track which pipelines were triggered
   161→    const triggeredPipelineIds: string[] = [];
   162→
   163→    // Execute each matched pipeline
   164→    for (const match of matches) {
   165→      const pipeline = activePipelines.find((p) => p.id === match.pipelineId);
   166→      if (!pipeline) continue;
   167→
   168→      const steps = stepsByPipeline.get(pipeline.id) ?? [];
   169→      if (steps.length === 0) continue;
   170→
   171→      // Depth check
   172→      if (chainDepth >= pipeline.maxPipelineDepth) {
   173→        continue;
   174→      }
   175→
   176→      // Concurrency check
   177→      const shouldSkip = await this.checkConcurrency(pipeline);
   178→      if (shouldSkip) continue;
   179→
   180→      triggeredPipelineIds.push(pipeline.id);
   181→
   182→      // Fire and track the execution
   183→      const executionPromise = this.executePipeline(
   184→        pipeline,
   185→        steps,
   186→        triggerEventId,
   187→        match.triggerPayload,
   188→        chainDepth,
   189→      ).catch((err) => {
   190→        console.error(
   191→          `[PipelineExecutor] Unhandled error executing pipeline ${pipeline.id}:`,
   192→          err instanceof Error ? err.message : String(err),
   193→        );
   194→      });
   195→
   196→      this.inFlightExecutions.add(executionPromise);
   197→      executionPromise.finally(() => {
   198→        this.inFlightExecutions.delete(executionPromise);
   199→      });
   200→    }
   201→
   202→    // Update trigger event as processed
   203→    await this.db
   204→      .update(triggerEvents)
   205→      .set({
   206→        status: 'processed',
   207→        processedAt: new Date(),
   208→        pipelinesTriggered: triggeredPipelineIds,
   209→      })
   210→      .where(eq(triggerEvents.id, triggerEventId));
   211→  }
   212→
   213→  // ----------------------------------------------------------
   214→  // PIPELINE EXECUTION
   215→  // ----------------------------------------------------------
   216→
   217→  /**
   218→   * Execute a single pipeline: create execution record, create step records,
   219→   * run steps sequentially.
   220→   */
   221→  private async executePipeline(
   222→    pipeline: Pipeline,
   223→    steps: PipelineStep[],
   224→    triggerEventId: string,
   225→    triggerPayload: Record<string, unknown>,
   226→    chainDepth: number,
   227→  ): Promise<void> {
   228→    const executionId = createId();
   229→
   230→    // Create pipeline_executions record
   231→    await this.db.insert(pipelineExecutions).values({
   232→      id: executionId,
   233→      pipelineId: pipeline.id,
   234→      tenantId: pipeline.tenantId,
   235→      triggerEventId,
   236→      status: 'running',
   237→      stepsTotal: steps.length,
   238→      stepsCompleted: 0,
   239→      currentStepPosition: 0,
   240→      triggerChainDepth: chainDepth,
   241→      outputArtifacts: [],
   242→    });
   243→
   244→    // Create all execution_step records upfront
   245→    const execStepRecords = steps.map((step) => ({
   246→      id: createId(),
   247→      executionId,
   248→      stepId: step.id,
   249→      position: step.position,
   250→      status: 'pending' as const,
   251→      attempts: 0,
   252→      idempotencyKey: computeIdempotencyKey(executionId, step.id, 0),
   253→    }));
   254→
   255→    await this.db.insert(executionSteps).values(execStepRecords);
   256→
   257→    // Run steps sequentially
   258→    const previousStepOutputs = new Map<number, Record<string, unknown>>();
   259→    let stepsCompleted = 0;
   260→
   261→    for (let i = 0; i < steps.length; i++) {
   262→      const step = steps[i];
   263→      const execStep = execStepRecords[i];
   264→
   265→      // Review gate placeholder (WP06)
   266→      if (step.stepType === 'review_gate') {
   267→        await this.db
   268→          .update(pipelineExecutions)
   269→          .set({
   270→            status: 'paused_at_gate',
   271→            currentStepPosition: step.position,
   272→          })
   273→          .where(eq(pipelineExecutions.id, executionId));
   274→
   275→        await this.db
   276→          .update(executionSteps)
   277→          .set({ status: 'pending' })
   278→          .where(eq(executionSteps.id, execStep.id));
   279→        return;
   280→      }
   281→
   282→      // Build execution context
   283→      const context: ExecutionContext = {
   284→        tenantId: pipeline.tenantId,
   285→        executionId,
   286→        pipelineId: pipeline.id,
   287→        triggerPayload,
   288→        previousStepOutputs,
   289→      };
   290→
   291→      // Run the step
   292→      const retryPolicy = (pipeline.retryPolicy as RetryPolicy | null) ?? DEFAULT_RETRY_POLICY;
   293→      const result = await this.stepRunner.runStep(
   294→        execStep.id,
   295→        step,
   296→        context,
   297→        retryPolicy,
   298→      );
   299→
   300→      if (result.success || result.isNoOp) {
   301→        stepsCompleted++;
   302→        if (result.outputData) {
   303→          previousStepOutputs.set(step.position, result.outputData);
   304→        }
   305→        await this.db
   306→          .update(pipelineExecutions)
   307→          .set({
   308→            stepsCompleted,
   309→            currentStepPosition: step.position,
   310→          })
   311→          .where(eq(pipelineExecutions.id, executionId));
   312→      } else {
   313→        // Step failed — pause execution
   314→        await this.db
   315→          .update(pipelineExecutions)
   316→          .set({
   317→            status: 'paused_on_failure',
   318→            currentStepPosition: step.position,
   319→            errorDetail: result.error ?? { message: 'Step failed' },
   320→          })
   321→          .where(eq(pipelineExecutions.id, executionId));
   322→        return;
   323→      }
   324→    }
   325→
   326→    // All steps completed
   327→    await this.db
   328→      .update(pipelineExecutions)
   329→      .set({
   330→        status: 'completed',
   331→        completedAt: new Date(),
   332→        stepsCompleted,
   333→      })
   334→      .where(eq(pipelineExecutions.id, executionId));
   335→  }
   336→
   337→  // ----------------------------------------------------------
   338→  // CONCURRENCY
   339→  // ----------------------------------------------------------
   340→
   341→  /**
   342→   * Check concurrency policy for a pipeline.
   343→   * Returns true if the pipeline execution should be skipped.
   344→   */
   345→  private async checkConcurrency(pipeline: Pipeline): Promise<boolean> {
   346→    if (pipeline.concurrencyPolicy === 'allow_concurrent') return false;
   347→
   348→    const nonTerminalStatuses = ['pending', 'running', 'paused_at_gate'] as const;
   349→
   350→    const existing = await this.db
   351→      .select()
   352→      .from(pipelineExecutions)
   353→      .where(
   354→        and(
   355→          eq(pipelineExecutions.pipelineId, pipeline.id),
   356→          inArray(pipelineExecutions.status, [...nonTerminalStatuses]),
   357→        ),
   358→      );
   359→
   360→    if (existing.length > 0 && pipeline.concurrencyPolicy === 'skip_if_running') {
   361→      return true;
   362→    }
   363→
   364→    // 'queue' policy: for now, also skip (queuing is a WP07+ concern)
   365→    if (existing.length > 0 && pipeline.concurrencyPolicy === 'queue') {
   366→      return true;
   367→    }
   368→
   369→    return false;
   370→  }
   371→}
