     1→/**
     2→ * ProfileGenerationHandler — regenerates one or more profiles via the profile engine.
     3→ */
     4→
     5→import type { StepType, StepResult } from '../types.js';
     6→import type { ExecutionContext } from '../engine/step-runner.js';
     7→import type { PipelineStepHandler, StepHandlerDependencies } from './interface.js';
     8→
     9→export class ProfileGenerationHandler implements PipelineStepHandler {
    10→  readonly stepType: StepType = 'profile_generation';
    11→
    12→  constructor(private readonly deps: StepHandlerDependencies) {}
    13→
    14→  validateConfig(config: Record<string, unknown>): string[] {
    15→    const errors: string[] = [];
    16→    if (
    17→      !Array.isArray(config['profileIds']) ||
    18→      (config['profileIds'] as unknown[]).length === 0
    19→    ) {
    20→      errors.push('profileIds must be a non-empty array of strings');
    21→    }
    22→    return errors;
    23→  }
    24→
    25→  async execute(config: Record<string, unknown>, _context: ExecutionContext): Promise<StepResult> {
    26→    if (!this.deps.profileEngine) {
    27→      return {
    28→        success: false,
    29→        error: {
    30→          message: 'Profile engine client not configured',
    31→          type: 'configuration',
    32→          isTransient: false,
    33→          retryable: false,
    34→        },
    35→      };
    36→    }
    37→
    38→    const profileIds = config['profileIds'] as string[];
    39→    const results: Array<{ profileId: string; success: boolean; durationMs?: number }> = [];
    40→
    41→    try {
    42→      for (const profileId of profileIds) {
    43→        const result = await this.deps.profileEngine.regenerateProfile(profileId);
    44→        results.push(result);
    45→      }
    46→    } catch (err) {
    47→      const message = err instanceof Error ? err.message : String(err);
    48→      const isNetwork = /network|timeout|ECONNREFUSED|ETIMEDOUT/i.test(message);
    49→      return {
    50→        success: false,
    51→        error: {
    52→          message,
    53→          type: isNetwork ? 'network' : 'service_error',
    54→          isTransient: isNetwork,
    55→          retryable: isNetwork,
    56→        },
    57→      };
    58→    }
    59→
    60→    const failed = results.filter((r) => !r.success);
    61→    if (failed.length > 0) {
    62→      return {
    63→        success: false,
    64→        error: {
    65→          message: `Failed to regenerate profiles: ${failed.map((r) => r.profileId).join(', ')}`,
    66→          type: 'service_error',
    67→          isTransient: false,
    68→          retryable: false,
    69→        },
    70→      };
    71→    }
    72→
    73→    return {
    74→      success: true,
    75→      outputData: { regenerated: results },
    76→    };
    77→  }
    78→}
