     1→/**
     2→ * FidelityCheckHandler — runs a fidelity check against a profile and content set.
     3→ *
     4→ * A low score is a successful check result with passed=false, NOT a step failure.
     5→ */
     6→
     7→import type { StepType, StepResult } from '../types.js';
     8→import type { ExecutionContext } from '../engine/step-runner.js';
     9→import type { PipelineStepHandler, StepHandlerDependencies } from './interface.js';
    10→
    11→export class FidelityCheckHandler implements PipelineStepHandler {
    12→  readonly stepType: StepType = 'fidelity_check';
    13→
    14→  constructor(private readonly deps: StepHandlerDependencies) {}
    15→
    16→  validateConfig(config: Record<string, unknown>): string[] {
    17→    const errors: string[] = [];
    18→    if (!config['profileId'] || typeof config['profileId'] !== 'string') {
    19→      errors.push('profileId must be a non-empty string');
    20→    }
    21→    const hasContentIds = Array.isArray(config['contentIds']) && (config['contentIds'] as unknown[]).length > 0;
    22→    const hasUpstream = config['useUpstreamOutputs'] === true;
    23→    if (!hasContentIds && !hasUpstream) {
    24→      errors.push('contentIds (non-empty array) or useUpstreamOutputs=true is required');
    25→    }
    26→    return errors;
    27→  }
    28→
    29→  async execute(config: Record<string, unknown>, context: ExecutionContext): Promise<StepResult> {
    30→    if (!this.deps.contentIntelligence) {
    31→      return {
    32→        success: false,
    33→        error: {
    34→          message: 'Content intelligence client not configured',
    35→          type: 'configuration',
    36→          isTransient: false,
    37→          retryable: false,
    38→        },
    39→      };
    40→    }
    41→
    42→    const profileId = config['profileId'] as string;
    43→    let contentIds: string[] = Array.isArray(config['contentIds'])
    44→      ? (config['contentIds'] as string[])
    45→      : [];
    46→
    47→    // Resolve upstream outputs if requested
    48→    if (config['useUpstreamOutputs'] === true && contentIds.length === 0) {
    49→      for (const [, output] of context.previousStepOutputs) {
    50→        const artifactId = output['artifactId'];
    51→        if (typeof artifactId === 'string') {
    52→          contentIds.push(artifactId);
    53→        }
    54→      }
    55→    }
    56→
    57→    try {
    58→      const result = await this.deps.contentIntelligence.runFidelityCheck(profileId, contentIds);
    59→      return {
    60→        success: true,
    61→        outputData: {
    62→          score: result.score,
    63→          passed: result.passed,
    64→          details: result.details ?? {},
    65→        },
    66→      };
    67→    } catch (err) {
    68→      const message = err instanceof Error ? err.message : String(err);
    69→      const isNetwork = /network|timeout|ECONNREFUSED|ETIMEDOUT/i.test(message);
    70→      return {
    71→        success: false,
    72→        error: {
    73→          message,
    74→          type: isNetwork ? 'network' : 'service_error',
    75→          isTransient: isNetwork,
    76→          retryable: isNetwork,
    77→        },
    78→      };
    79→    }
    80→  }
    81→}
