     1→/**
     2→ * Corpus-Change Trigger Handler
     3→ *
     4→ * Matches active pipelines that listen for corpus_change events.
     5→ * Applies optional corpus filter and enforces max pipeline depth.
     6→ */
     7→
     8→import type { TriggerEventType, CorpusChangeTriggerConfig } from '../types.js';
     9→import { DEFAULT_MAX_PIPELINE_DEPTH } from '../types.js';
    10→import type { Pipeline } from '../schema.js';
    11→import type { TriggerHandler, TriggerContext, TriggerResult } from './interface.js';
    12→
