    44→
    45→  /**
    46→   * Remove a previously registered subscription.
    47→   */
    48→  unsubscribe(subscriptionId: string): void;
    49→
    50→  /**
    51→   * Gracefully shut down the bus and release resources.
    52→   */
    53→  close(): Promise<void>;
    54→}
    55→
    56→// ============================================================
    57→// IN-MEMORY IMPLEMENTATION (testing)
    58→// ============================================================
    59→
    60→interface Subscription {
    61→  eventType: TriggerEventType;
    62→  handler: EventHandler;
    63→}
    64→
    65→export class InMemoryEventBus implements EventBus {
    66→  private readonly subscriptions = new Map<string, Subscription>();
    67→
    68→  async publish(
    69→    tenantId: string,
    70→    eventType: TriggerEventType,
    71→    payload: Record<string, unknown>,
    72→  ): Promise<string> {
    73→    const id = createId();
    74→    const envelope: EventEnvelope = { id, tenantId, eventType, payload, createdAt: new Date() };
    75→
    76→    for (const sub of this.subscriptions.values()) {
