// Minimal Inngest step API surface we depend on
interface InngestStep {
  run<T>(name: string, fn: () => Promise<T>): Promise<T>;
}

interface InngestStepHandlerAdapter {
  run(
    step: InngestStep,
    stepName: string,
    config: Record<string, unknown>,
    context: ExecutionContext,
  ): Promise<StepResult>;
}

function createInngestAdapter(handler: PipelineStepHandler): InngestStepHandlerAdapter
```

The implementation is simple: `return step.run(stepName, () => handler.execute(config, context))`.

