### T006: `src/inngest/adapter.ts`

Create `InngestStepHandlerAdapter` interface and `createInngestAdapter` factory:

```typescript
// Minimal Inngest step API surface we depend on
interface InngestStep {
  run<T>(name: string, fn: () => Promise<T>): Promise<T>;
}

interface InngestStepHandlerAdapter {
  run(
    step: InngestStep,
    stepName: string,
    config: Record<string, unknown>,
    context: ExecutionContext,
  ): Promise<StepResult>;
