   173→app.post('/mcp', requireBearerToken, async (req: Request, res: Response) => {
   174→  const user = req.mcpUser!;
   175→
   176→  // Handle MCP request
   177→  const { method, params, id } = req.body;
   178→
   179→  try {
   180→    let result;
   181→
   182→    switch (method) {
   183→      case 'initialize':
   184→        result = {
   185→          protocolVersion: '2024-11-05',
   186→          capabilities: {
   187→            tools: {}
   188→          },
   189→          serverInfo: {
   190→            name: 'jawn-ai-mcp-server',
   191→            version: '0.1.0'
   192→          }
   193→        };
   194→        break;
   195→
   196→      case 'tools/list': {
   197→        const tools = await getAllTools(user.id);
   198→        result = { tools };
   199→        break;
   200→      }
   201→
   202→      case 'tools/call': {
   203→        const { name, arguments: args } = params;
   204→        const startTime = Date.now();
   205→
   206→        try {
   207→          const toolResult = await executeTool(user.id, name, args || {});
   208→
   209→          // Audit log
   210→          await db.insert(auditLogs).values({
   211→            userId: user.id,
   212→            tool: name,
   213→            input: args || {},
   214→            success: true,
   215→            duration: Date.now() - startTime
   216→          });
   217→
   218→          result = {
   219→            content: [{ type: 'text', text: JSON.stringify(toolResult, null, 2) }]
   220→          };
   221→        } catch (toolError: unknown) {
   222→          const errorMessage = toolError instanceof Error ? toolError.message : 'Unknown error';
   223→
   224→          // Audit log failure
   225→          await db.insert(auditLogs).values({
   226→            userId: user.id,
   227→            tool: name,
   228→            input: args || {},
   229→            success: false,
   230→            error: errorMessage,
   231→            duration: Date.now() - startTime
   232→          });
   233→
   234→          result = {
   235→            content: [{ type: 'text', text: `Error: ${errorMessage}` }],
   236→            isError: true
   237→          };
   238→        }
   239→        break;
   240→      }
   241→
   242→      default:
   243→        return res.status(400).json({
   244→          jsonrpc: '2.0',
   245→          id,
   246→          error: { code: -32601, message: `Method not found: ${method}` }
   247→        });
   248→    }
   249→
   250→    res.json({
   251→      jsonrpc: '2.0',
   252→      id,
   253→      result
   254→    });
   255→  } catch (error: unknown) {
   256→    const errorMessage = error instanceof Error ? error.message : 'Unknown error';
   257→    console.error('MCP error:', error);
   258→    res.json({
   259→      jsonrpc: '2.0',
   260→      id,
   261→      error: { code: -32603, message: errorMessage }
   262→    });
   263→  }
   264→});
