   317→    pipelineModule = await initializePipelineModule({
   318→      db: db as unknown as import('drizzle-orm/node-postgres').NodePgDatabase,
   319→      connectionString: process.env.DATABASE_URL ?? '',
   320→    });
   321→
   322→    // Mount pipeline routes
   323→    app.use('/api', pipelineModule.router);
   324→
   325→    // Inject pipeline deps into tool executor
   326→    setPipelineContext({
   327→      stepRegistry: pipelineModule.stepRegistry,
   328→      decisionRecorder: pipelineModule.decisionRecorder,
