     1→/**
     2→ * StepRunner — executes a single pipeline step with retry logic.
     3→ *
     4→ * Looks up the appropriate handler from a StepHandlerRegistry,
     5→ * manages retry attempts with exponential backoff, checks idempotency,
     6→ * and updates the execution_step DB record throughout.
     7→ */
     8→
     9→import { eq } from 'drizzle-orm';
    10→import type { NodePgDatabase } from 'drizzle-orm/node-postgres';
    11→import type { StepType, RetryPolicy, StepResult, StepError } from '../types.js';
    12→import { DEFAULT_RETRY_POLICY } from '../types.js';
    13→import type { PipelineStep } from '../schema.js';
    14→import { executionSteps } from '../schema.js';
    15→import { computeIdempotencyKey, checkIdempotency } from './idempotency.js';
    16→import { shouldRetry, waitForRetry } from './retry.js';
    17→
    18→// ============================================================
    19→// INTERFACES
    20→// ============================================================
    21→
    22→/** Context passed to step handlers during execution. */
    23→export interface ExecutionContext {
    24→  tenantId: string;
    25→  executionId: string;
    26→  pipelineId: string;
    27→  triggerPayload: Record<string, unknown>;
    28→  previousStepOutputs: Map<number, Record<string, unknown>>;
    29→}
    30→
    31→/** Interface for step handlers (implemented in WP05). */
    32→export interface PipelineStepHandler {
    33→  readonly stepType: StepType;
    34→  execute(
    35→    config: Record<string, unknown>,
    36→    context: ExecutionContext,
    37→  ): Promise<StepResult>;
    38→}
    39→
    40→/** Lookup step handlers by type (implemented in WP05). */
    41→export interface StepHandlerRegistry {
    42→  getHandler(stepType: StepType): PipelineStepHandler | undefined;
    43→}
    44→
    45→// ============================================================
    46→// STEP RUNNER
    47→// ============================================================
    48→
    49→export class StepRunner {
    50→  constructor(
    51→    private readonly db: NodePgDatabase,
    52→    private readonly registry: StepHandlerRegistry,
    53→  ) {}
    54→
    55→  /**
    56→   * Run a single pipeline step, managing retries and DB state.
    57→   *
    58→   * @param executionStepId  - ID of the execution_steps row
    59→   * @param pipelineStep     - The pipeline_steps definition (type, config, retry override)
    60→   * @param context          - Execution context with tenant, pipeline, trigger data
    61→   * @param retryPolicy      - Pipeline-level retry policy (step override takes precedence)
    62→   */
    63→  async runStep(
    64→    executionStepId: string,
    65→    pipelineStep: PipelineStep,
    66→    context: ExecutionContext,
    67→    retryPolicy?: RetryPolicy,
    68→  ): Promise<StepResult> {
    69→    const effectivePolicy: RetryPolicy =
    70→      (pipelineStep.retryPolicyOverride as RetryPolicy | null) ?? retryPolicy ?? DEFAULT_RETRY_POLICY;
    71→
    72→    // Mark step as running
    73→    await this.db
    74→      .update(executionSteps)
    75→      .set({ status: 'running', startedAt: new Date() })
    76→      .where(eq(executionSteps.id, executionStepId));
    77→
    78→    // Look up handler
    79→    const handler = this.registry.getHandler(pipelineStep.stepType);
    80→    if (!handler) {
    81→      const errorResult: StepResult = {
    82→        success: false,
    83→        error: {
    84→          message: `No handler registered for step type: ${pipelineStep.stepType}`,
    85→          type: 'HANDLER_NOT_FOUND',
    86→          isTransient: false,
    87→          retryable: false,
    88→        },
    89→      };
    90→      await this.db
    91→        .update(executionSteps)
    92→        .set({
    93→          status: 'failed',
    94→          completedAt: new Date(),
    95→          errorDetail: errorResult.error,
    96→        })
    97→        .where(eq(executionSteps.id, executionStepId));
    98→      return errorResult;
    99→    }
   100→
   101→    // Retry loop
   102→    let attempt = 0;
   103→    let lastError: StepError | undefined;
   104→
   105→    while (attempt <= effectivePolicy.maxRetries) {
   106→      // Idempotency check
   107→      const idempotencyKey = computeIdempotencyKey(
   108→        context.executionId,
   109→        pipelineStep.id,
   110→        attempt,
   111→      );
   112→      const cached = await checkIdempotency(this.db, idempotencyKey);
   113→      if (cached) {
   114→        const noOpResult: StepResult = { success: true, outputData: cached, isNoOp: true };
   115→        await this.db
   116→          .update(executionSteps)
   117→          .set({
   118→            status: 'no_op',
   119→            completedAt: new Date(),
   120→            outputData: cached,
   121→            idempotencyKey,
   122→            attempts: attempt + 1,
   123→          })
   124→          .where(eq(executionSteps.id, executionStepId));
   125→        return noOpResult;
   126→      }
   127→
   128→      // Update attempt counter and idempotency key
   129→      await this.db
   130→        .update(executionSteps)
   131→        .set({ attempts: attempt + 1, idempotencyKey })
   132→        .where(eq(executionSteps.id, executionStepId));
   133→
   134→      try {
   135→        const result = await handler.execute(
   136→          pipelineStep.config as Record<string, unknown>,
   137→          context,
   138→        );
   139→
   140→        if (result.success) {
   141→          const finalStatus = result.isNoOp ? 'no_op' as const : 'completed' as const;
   142→          await this.db
   143→            .update(executionSteps)
   144→            .set({
   145→              status: finalStatus,
   146→              completedAt: new Date(),
   147→              outputData: result.outputData ?? null,
   148→            })
   149→            .where(eq(executionSteps.id, executionStepId));
   150→          return result;
   151→        }
   152→
   153→        // Handler returned failure
   154→        lastError = result.error ?? {
   155→          message: 'Step handler returned failure without error details',
   156→          type: 'UNKNOWN',
   157→          isTransient: false,
   158→          retryable: false,
   159→        };
   160→      } catch (err) {
   161→        // Handler threw an exception — treat as transient
   162→        lastError = {
   163→          message: err instanceof Error ? err.message : String(err),
   164→          type: 'EXCEPTION',
   165→          isTransient: true,
   166→          retryable: true,
   167→        };
   168→      }
   169→
   170→      // Decide whether to retry (attempt is 0-indexed; shouldRetry compares against maxRetries)
   171→      const retryDecision = shouldRetry(lastError, attempt, effectivePolicy);
   172→      if (!retryDecision.retry) break;
   173→
   174→      await waitForRetry(retryDecision.delayMs!);
   175→      attempt++;
   176→    }
   177→
   178→    // All retries exhausted or non-transient error
   179→    const failResult: StepResult = { success: false, error: lastError };
   180→    await this.db
   181→      .update(executionSteps)
   182→      .set({
   183→        status: 'failed',
   184→        completedAt: new Date(),
   185→        errorDetail: lastError,
   186→      })
   187→      .where(eq(executionSteps.id, executionStepId));
   188→    return failResult;
   189→  }
   190→}
   191→

