     7→
     8→// ============================================================
     9→// ENUM MIRRORS (string literal unions)
    10→// ============================================================
    11→
    12→export type PipelineStatus = 'active' | 'paused' | 'disabled';
    13→
    14→export type ExecutionStatus =
