    16→  | 'completed' | 'failed' | 'cancelled';
    17→
    18→export type ExecutionStepStatus =
    19→  | 'pending' | 'running' | 'completed' | 'failed' | 'skipped' | 'no_op';
    20→
    21→export type TriggerEventType = 'corpus_change' | 'schedule_tick' | 'manual_request';
    22→
    23→export type TriggerEventStatus = 'pending' | 'acknowledged' | 'processed' | 'failed' | 'expired';
    24→
    25→export type StepType =
    26→  | 'profile_generation' | 'fidelity_check' | 'content_generation'
    27→  | 'source_query' | 'review_gate' | 'notification';
