    61→}
    62→
    63→export type TriggerConfig =
    64→  | CorpusChangeTriggerConfig
    65→  | ScheduleTriggerConfig
    66→  | ManualRequestTriggerConfig;
    67→
    68→// --- Step configs (discriminated on `type`) ---
    69→
    70→export interface ProfileGenerationStepConfig {
