     1→/**
     2→ * DecisionRecorder — records reviewer decisions on pending artifacts and,
     3→ * once all decisions for a gate step are complete, resumes the execution.
     4→ */
     5→
     6→import { eq, and } from 'drizzle-orm';
     7→import type { NodePgDatabase } from 'drizzle-orm/node-postgres';
     8→import {
     9→  reviewDecisions,
    10→  executionSteps,
    11→  pipelineExecutions,
    12→} from '../schema.js';
    13→import type { ReviewDecision } from '../schema.js';
    14→import type { ArtifactRef, ReviewFeedback } from '../types.js';
    15→
    16→// ============================================================
    17→// REVIEW GATE RESULT (appended to outputArtifacts on resume)
    18→// ============================================================
    19→
    20→export interface ReviewGateResult {
    21→  gateStepPosition: number;
    22→  approvedArtifacts: ArtifactRef[];
    23→  rejectedArtifacts: Array<{ artifact: ArtifactRef; feedback: ReviewFeedback | null }>;
    24→  approvalRate: number;
    25→}
    26→
    27→// ============================================================
    28→// DECISION RECORDER
    29→// ============================================================
    30→
    31→export class DecisionRecorder {
    32→  constructor(private readonly db: NodePgDatabase) {}
    33→
    34→  /**
    35→   * Record a single reviewer decision (approve or reject) for a pending
    36→   * review_decision row.
    37→   *
    38→   * Enforces:
    39→   *  - Tenant isolation: decision must belong to the supplied tenantId
    40→   *  - No duplicate decisions: status must be 'pending'
    41→   *
    42→   * When all decisions for the gate step are complete the execution is
    43→   * automatically resumed so the executor poll loop can continue.
    44→   */
    45→  async recordDecision(
    46→    decisionId: string,
    47→    tenantId: string,
    48→    status: 'approved' | 'rejected',
    49→    reviewerId: string,
    50→    feedback?: ReviewFeedback,
    51→  ): Promise<{ allDecisionsComplete: boolean; executionId: string }> {
    52→    // Load the decision
    53→    const rows = await this.db
    54→      .select()
    55→      .from(reviewDecisions)
    56→      .where(eq(reviewDecisions.id, decisionId));
    57→
    58→    if (rows.length === 0) {
    59→      throw new Error(`Review decision not found: ${decisionId}`);
    60→    }
    61→
    62→    const decision = rows[0] as ReviewDecision;
    63→
    64→    // Tenant isolation
    65→    if (decision.tenantId !== tenantId) {
    66→      throw new Error(`Cross-tenant access denied for decision: ${decisionId}`);
    67→    }
    68→
    69→    // No duplicate decisions
    70→    if (decision.status !== 'pending') {
    71→      throw new Error(
    72→        `Decision ${decisionId} already resolved with status '${decision.status}'`,
    73→      );
    74→    }
    75→
    76→    // Persist the decision
    77→    await this.db
    78→      .update(reviewDecisions)
    79→      .set({
    80→        status,
    81→        reviewerId,
    82→        decidedAt: new Date(),
    83→        feedback: status === 'rejected' && feedback
    84→          ? (feedback as unknown as Record<string, unknown>)
    85→          : null,
    86→      })
    87→      .where(eq(reviewDecisions.id, decisionId));
    88→
    89→    const allDecisionsComplete = await this.areAllDecisionsComplete(
    90→      decision.executionId,
    91→      decision.executionStepId,
    92→    );
    93→
    94→    if (allDecisionsComplete) {
    95→      await this.resumeExecution(decision.executionId);
    96→    }
    97→
    98→    return { allDecisionsComplete, executionId: decision.executionId };
    99→  }
   100→
   101→  /**
   102→   * Returns true when no decision for the given step is still 'pending'.
   103→   */
   104→  async areAllDecisionsComplete(
   105→    executionId: string,
   106→    executionStepId: string,
   107→  ): Promise<boolean> {
   108→    const pending = await this.db
   109→      .select()
   110→      .from(reviewDecisions)
   111→      .where(
   112→        and(
   113→          eq(reviewDecisions.executionId, executionId),
   114→          eq(reviewDecisions.executionStepId, executionStepId),
   115→          eq(reviewDecisions.status, 'pending'),
   116→        ),
   117→      );
   118→
   119→    return pending.length === 0;
   120→  }
   121→
   122→  /**
   123→   * Build the ReviewGateResult summary, mark the gate step completed, and
   124→   * set the execution status back to 'running' so the executor can continue.
   125→   */
   126→  private async resumeExecution(executionId: string): Promise<void> {
   127→    // Load all decisions for this execution
   128→    const allDecisions = await this.db
   129→      .select()
   130→      .from(reviewDecisions)
   131→      .where(eq(reviewDecisions.executionId, executionId));
   132→
   133→    if (allDecisions.length === 0) return;
   134→
   135→    // Partition approved vs rejected
   136→    const approved: ArtifactRef[] = [];
   137→    const rejected: Array<{ artifact: ArtifactRef; feedback: ReviewFeedback | null }> = [];
   138→
   139→    for (const d of allDecisions) {
   140→      const artifact = d.artifactRef as unknown as ArtifactRef;
   141→      if (d.status === 'approved') {
   142→        approved.push(artifact);
   143→      } else if (d.status === 'rejected') {
   144→        rejected.push({
   145→          artifact,
   146→          feedback: (d.feedback as unknown as ReviewFeedback | null) ?? null,
   147→        });
   148→      }
   149→    }
   150→
   151→    const total = approved.length + rejected.length;
   152→    const approvalRate = total > 0 ? approved.length / total : 0;
   153→
   154→    // Load the gate execution step to get its position
   155→    const gateStepId = allDecisions[0].executionStepId;
   156→    const stepRows = await this.db
   157→      .select()
