    const registry = makeRegistry();
    const inngestFn = createCorpusUpdatePipeline(registry) as unknown as {
      fn: (args: { event: unknown; step: InngestStep }) => Promise<Record<string, unknown>>;
    };

    const step = makeReviewStep({
