     1→/**
     2→ * DecisionRecorder — records reviewer decisions on pending artifacts and,
     3→ * once all decisions for a gate step are complete, resumes the execution.
     4→ */
     5→
     6→import { eq, and } from 'drizzle-orm';
     7→import type { NodePgDatabase } from 'drizzle-orm/node-postgres';
     8→import {
     9→  reviewDecisions,
    10→  executionSteps,
    11→  pipelineExecutions,
    12→} from '../schema.js';
    13→import type { ReviewDecision } from '../schema.js';
    14→import type { ArtifactRef, ReviewFeedback } from '../types.js';
    15→import { inngest } from '../../inngest/client.js';
    16→
    17→// ============================================================
    18→// REVIEW GATE RESULT (appended to outputArtifacts on resume)
    19→// ============================================================
    20→
    21→export interface ReviewGateResult {
    22→  gateStepPosition: number;
    23→  approvedArtifacts: ArtifactRef[];
    24→  rejectedArtifacts: Array<{ artifact: ArtifactRef; feedback: ReviewFeedback | null }>;
    25→  approvalRate: number;
    26→}
    27→
    28→// ============================================================
    29→// DECISION RECORDER
    30→// ============================================================
    31→
    32→export class DecisionRecorder {
    33→  constructor(private readonly db: NodePgDatabase) {}
    34→
    35→  /**
    36→   * Record a single reviewer decision (approve or reject) for a pending
    37→   * review_decision row.
    38→   *
    39→   * Enforces:
    40→   *  - Tenant isolation: decision must belong to the supplied tenantId
    41→   *  - No duplicate decisions: status must be 'pending'
    42→   *
    43→   * When all decisions for the gate step are complete the execution is
    44→   * automatically resumed so the executor poll loop can continue.
    45→   */
    46→  async recordDecision(
    47→    decisionId: string,
    48→    tenantId: string,
    49→    status: 'approved' | 'rejected',
    50→    reviewerId: string,
    51→    feedback?: ReviewFeedback,
    52→  ): Promise<{ allDecisionsComplete: boolean; executionId: string }> {
    53→    // Load the decision
    54→    const rows = await this.db
    55→      .select()
    56→      .from(reviewDecisions)
    57→      .where(eq(reviewDecisions.id, decisionId));
    58→
    59→    if (rows.length === 0) {
    60→      throw new Error(`Review decision not found: ${decisionId}`);
    61→    }
    62→
    63→    const decision = rows[0] as ReviewDecision;
    64→
    65→    // Tenant isolation
    66→    if (decision.tenantId !== tenantId) {
    67→      throw new Error(`Cross-tenant access denied for decision: ${decisionId}`);
    68→    }
    69→
    70→    // No duplicate decisions
    71→    if (decision.status !== 'pending') {
    72→      throw new Error(
    73→        `Decision ${decisionId} already resolved with status '${decision.status}'`,
    74→      );
    75→    }
    76→
    77→    // Persist the decision
    78→    await this.db
    79→      .update(reviewDecisions)
    80→      .set({
    81→        status,
    82→        reviewerId,
    83→        decidedAt: new Date(),
    84→        feedback: status === 'rejected' && feedback
    85→          ? (feedback as unknown as Record<string, unknown>)
    86→          : null,
    87→      })
    88→      .where(eq(reviewDecisions.id, decisionId));
    89→
    90→    const allDecisionsComplete = await this.areAllDecisionsComplete(
    91→      decision.executionId,
    92→      decision.executionStepId,
    93→    );
    94→
    95→    if (allDecisionsComplete) {
    96→      await this.resumeExecution(decision.executionId);
    97→
    98→      // Send Inngest event to resume the paused review-gate step
    99→      await inngest.send({
   100→        name: 'pipeline/review.decided',
   101→        data: {
   102→          tenantId: decision.tenantId,
   103→          executionId: decision.executionId,
   104→          decision: status,
   105→          feedback: status === 'rejected' && feedback ? feedback.reason : undefined,
   106→        },
   107→      });
   108→    }
   109→
   110→    return { allDecisionsComplete, executionId: decision.executionId };
   111→  }
   112→
   113→  /**
   114→   * Returns true when no decision for the given step is still 'pending'.
   115→   */
   116→  async areAllDecisionsComplete(
   117→    executionId: string,
   118→    executionStepId: string,
   119→  ): Promise<boolean> {
   120→    const pending = await this.db
   121→      .select()
   122→      .from(reviewDecisions)
   123→      .where(
   124→        and(
   125→          eq(reviewDecisions.executionId, executionId),
   126→          eq(reviewDecisions.executionStepId, executionStepId),
   127→          eq(reviewDecisions.status, 'pending'),
   128→        ),
   129→      );
   130→
   131→    return pending.length === 0;
   132→  }
   133→
   134→  /**
   135→   * Build the ReviewGateResult summary, mark the gate step completed, and
   136→   * set the execution status back to 'running' so the executor can continue.
   137→   */
   138→  private async resumeExecution(executionId: string): Promise<void> {
   139→    // Load all decisions for this execution
   140→    const allDecisions = await this.db
   141→      .select()
   142→      .from(reviewDecisions)
   143→      .where(eq(reviewDecisions.executionId, executionId));
   144→
   145→    if (allDecisions.length === 0) return;
   146→
   147→    // Partition approved vs rejected
   148→    const approved: ArtifactRef[] = [];
   149→    const rejected: Array<{ artifact: ArtifactRef; feedback: ReviewFeedback | null }> = [];
   150→
   151→    for (const d of allDecisions) {
   152→      const artifact = d.artifactRef as unknown as ArtifactRef;
   153→      if (d.status === 'approved') {
   154→        approved.push(artifact);
   155→      } else if (d.status === 'rejected') {
   156→        rejected.push({
   157→          artifact,
   158→          feedback: (d.feedback as unknown as ReviewFeedback | null) ?? null,
   159→        });
   160→      }
   161→    }
   162→
   163→    const total = approved.length + rejected.length;
   164→    const approvalRate = total > 0 ? approved.length / total : 0;
   165→
   166→    // Load the gate execution step to get its position
   167→    const gateStepId = allDecisions[0].executionStepId;
   168→    const stepRows = await this.db
   169→      .select()
   170→      .from(executionSteps)
   171→      .where(eq(executionSteps.id, gateStepId));
   172→
   173→    const gateStepPosition = stepRows.length > 0 ? stepRows[0].position : 0;
   174→
   175→    const gateResult: ReviewGateResult = {
   176→      gateStepPosition,
   177→      approvedArtifacts: approved,
   178→      rejectedArtifacts: rejected,
   179→      approvalRate,
   180→    };
   181→
   182→    // Load existing outputArtifacts to append
   183→    const execRows = await this.db
   184→      .select()
   185→      .from(pipelineExecutions)
   186→      .where(eq(pipelineExecutions.id, executionId));
   187→
   188→    const existing = execRows.length > 0
   189→      ? (execRows[0].outputArtifacts as unknown[]) ?? []
   190→      : [];
   191→
   192→    const updatedArtifacts = [...existing, gateResult];
   193→
   194→    // Mark gate step completed
   195→    await this.db
   196→      .update(executionSteps)
   197→      .set({ status: 'completed', completedAt: new Date() })
   198→      .where(eq(executionSteps.id, gateStepId));
   199→
   200→    // Resume execution — the executor poll loop will continue from here
   201→    await this.db
   202→      .update(pipelineExecutions)
   203→      .set({
   204→        status: 'running',
   205→        outputArtifacts: updatedArtifacts as unknown as Record<string, unknown>[],
   206→      })
   207→      .where(eq(pipelineExecutions.id, executionId));
   208→  }
   209→}
