     1→/**
     2→ * Inngest client configuration — Feature 010 evaluation spike.
     3→ *
     4→ * Configured for self-hosted Inngest server. In development, the server
     5→ * runs via docker-compose.inngest.yml at http://localhost:8288.
     6→ *
     7→ * Required environment variables:
     8→ *   INNGEST_BASE_URL      — URL of self-hosted Inngest server (default: http://localhost:8288)
     9→ *   INNGEST_EVENT_KEY     — Event key for publishing events (default: local-dev-key)
    10→ *   INNGEST_SIGNING_KEY   — Signing key for request verification (default: local-signing-key)
    11→ */
    12→import { Inngest, EventSchemas } from 'inngest';
    13→
    14→// ---------------------------------------------------------------------------
    15→// Event schema definitions
    16→// ---------------------------------------------------------------------------
    17→
    18→/**
    19→ * Events used by the pipeline system.
    20→ * Add new event types here as WP02-WP04 introduce them.
    21→ */
    22→type PipelineEvents = {
    23→  /** Fired when a corpus changes, triggering corpus-change pipelines */
    24→  'pipeline/corpus.changed': {
    25→    data: {
    26→      tenantId: string;
    27→      corpusId: string;
    28→      changeType: 'created' | 'updated' | 'deleted';
    29→    };
    30→  };
    31→
    32→  /** Fired by DecisionRecorder to resume a paused review-gate execution */
    33→  'pipeline/review.decided': {
    34→    data: {
    35→      tenantId: string;
    36→      executionId: string;
    37→      decision: 'approved' | 'rejected';
    38→      feedback?: string;
    39→    };
    40→  };
    41→
    42→  /** Fired by schedule triggers to kick off schedule_tick pipelines */
    43→  'pipeline/schedule.tick': {
    44→    data: {
    45→      tenantId: string;
    46→      pipelineId: string;
    47→      scheduledAt: string;
    48→    };
    49→  };
    50→};
