    52→// ---------------------------------------------------------------------------
    53→// Client
    54→// ---------------------------------------------------------------------------
    55→
    56→export const inngest = new Inngest({
    57→  id: 'joyus-ai',
    58→  schemas: new EventSchemas().fromRecord<PipelineEvents>(),
    59→  eventKey: process.env.INNGEST_EVENT_KEY ?? 'local-dev-key',
    60→  baseUrl: process.env.INNGEST_BASE_URL ?? 'http://localhost:8288',
    61→});
