     1→/**
     2→ * DecisionRecorder — records reviewer decisions on pending artifacts and,
     3→ * once all decisions for a gate step are complete, resumes the execution.
     4→ */
     5→
     6→import { eq, and } from 'drizzle-orm';
     7→import type { NodePgDatabase } from 'drizzle-orm/node-postgres';
     8→import {
     9→  reviewDecisions,
    10→  executionSteps,
    11→  pipelineExecutions,
    12→} from '../schema.js';
    13→import type { ReviewDecision } from '../schema.js';
    14→import type { ArtifactRef, ReviewFeedback } from '../types.js';
    15→import { inngest } from '../../inngest/client.js';
    16→
    17→// ============================================================
    18→// REVIEW GATE RESULT (appended to outputArtifacts on resume)
    19→// ============================================================
    20→
    21→export interface ReviewGateResult {
    22→  gateStepPosition: number;
    23→  approvedArtifacts: ArtifactRef[];
    24→  rejectedArtifacts: Array<{ artifact: ArtifactRef; feedback: ReviewFeedback | null }>;
    25→  approvalRate: number;
    26→}
    27→
    28→// ============================================================
    29→// DECISION RECORDER
    30→// ============================================================
    31→
    32→export class DecisionRecorder {
    33→  constructor(private readonly db: NodePgDatabase) {}
    34→
    35→  /**
    36→   * Record a single reviewer decision (approve or reject) for a pending
    37→   * review_decision row.
    38→   *
    39→   * Enforces:
    40→   *  - Tenant isolation: decision must belong to the supplied tenantId
    41→   *  - No duplicate decisions: status must be 'pending'
    42→   *
    43→   * When all decisions for the gate step are complete the execution is
    44→   * automatically resumed so the executor poll loop can continue.
    45→   */
    46→  async recordDecision(
    47→    decisionId: string,
    48→    tenantId: string,
    49→    status: 'approved' | 'rejected',
    50→    reviewerId: string,
    51→    feedback?: ReviewFeedback,
    52→  ): Promise<{ allDecisionsComplete: boolean; executionId: string }> {
    53→    // Load the decision
    54→    const rows = await this.db
    55→      .select()
    56→      .from(reviewDecisions)
    57→      .where(eq(reviewDecisions.id, decisionId));
    58→
    59→    if (rows.length === 0) {
    60→      throw new Error(`Review decision not found: ${decisionId}`);
    61→    }
    62→
    63→    const decision = rows[0] as ReviewDecision;
    64→
    65→    // Tenant isolation
    66→    if (decision.tenantId !== tenantId) {
    67→      throw new Error(`Cross-tenant access denied for decision: ${decisionId}`);
    68→    }
    69→
    70→    // No duplicate decisions
    71→    if (decision.status !== 'pending') {
    72→      throw new Error(
    73→        `Decision ${decisionId} already resolved with status '${decision.status}'`,
    74→      );
    75→    }
    76→
    77→    // Persist the decision
    78→    await this.db
    79→      .update(reviewDecisions)
    80→      .set({
    81→        status,
    82→        reviewerId,
    83→        decidedAt: new Date(),
    84→        feedback: status === 'rejected' && feedback
    85→          ? (feedback as unknown as Record<string, unknown>)
    86→          : null,
    87→      })
    88→      .where(eq(reviewDecisions.id, decisionId));
    89→
    90→    const allDecisionsComplete = await this.areAllDecisionsComplete(
    91→      decision.executionId,
    92→      decision.executionStepId,
    93→    );
    94→
    95→    if (allDecisionsComplete) {
    96→      await this.resumeExecution(decision.executionId);
    97→
    98→      // Send Inngest event to resume the paused review-gate step.
    99→      // id is a deterministic idempotency key — prevents duplicate resumes if
   100→      // two reviewers submit their final decision concurrently.
   101→      await inngest.send({
   102→        id: `review-decided-${decision.executionId}`,
   103→        name: 'pipeline/review.decided',
   104→        data: {
   105→          tenantId: decision.tenantId,
   106→          executionId: decision.executionId,
   107→          decision: status,
   108→          feedback: status === 'rejected' && feedback ? feedback.reason : undefined,
   109→        },
   110→      });
   111→    }
   112→
   113→    return { allDecisionsComplete, executionId: decision.executionId };
   114→  }
   115→
   116→  /**
   117→   * Returns true when no decision for the given step is still 'pending'.
   118→   */
   119→  async areAllDecisionsComplete(
   120→    executionId: string,
   121→    executionStepId: string,
   122→  ): Promise<boolean> {
   123→    const pending = await this.db
   124→      .select()
   125→      .from(reviewDecisions)
   126→      .where(
   127→        and(
   128→          eq(reviewDecisions.executionId, executionId),
   129→          eq(reviewDecisions.executionStepId, executionStepId),
   130→          eq(reviewDecisions.status, 'pending'),
   131→        ),
   132→      );
   133→
   134→    return pending.length === 0;
   135→  }
   136→
   137→  /**
   138→   * Build the ReviewGateResult summary, mark the gate step completed, and
   139→   * set the execution status back to 'running' so the executor can continue.
   140→   */
   141→  private async resumeExecution(executionId: string): Promise<void> {
   142→    // Load all decisions for this execution
   143→    const allDecisions = await this.db
   144→      .select()
   145→      .from(reviewDecisions)
   146→      .where(eq(reviewDecisions.executionId, executionId));
   147→
   148→    if (allDecisions.length === 0) return;
   149→
   150→    // Partition approved vs rejected
   151→    const approved: ArtifactRef[] = [];
   152→    const rejected: Array<{ artifact: ArtifactRef; feedback: ReviewFeedback | null }> = [];
   153→
   154→    for (const d of allDecisions) {
   155→      const artifact = d.artifactRef as unknown as ArtifactRef;
   156→      if (d.status === 'approved') {
   157→        approved.push(artifact);
   158→      } else if (d.status === 'rejected') {
   159→        rejected.push({
   160→          artifact,
   161→          feedback: (d.feedback as unknown as ReviewFeedback | null) ?? null,
   162→        });
   163→      }
   164→    }
   165→
   166→    const total = approved.length + rejected.length;
   167→    const approvalRate = total > 0 ? approved.length / total : 0;
   168→
   169→    // Load the gate execution step to get its position
   170→    const gateStepId = allDecisions[0].executionStepId;
   171→    const stepRows = await this.db
   172→      .select()
   173→      .from(executionSteps)
   174→      .where(eq(executionSteps.id, gateStepId));
   175→
   176→    const gateStepPosition = stepRows.length > 0 ? stepRows[0].position : 0;
   177→
   178→    const gateResult: ReviewGateResult = {
   179→      gateStepPosition,
   180→      approvedArtifacts: approved,
   181→      rejectedArtifacts: rejected,
   182→      approvalRate,
   183→    };
   184→
   185→    // Load existing outputArtifacts to append
   186→    const execRows = await this.db
   187→      .select()
   188→      .from(pipelineExecutions)
   189→      .where(eq(pipelineExecutions.id, executionId));
   190→
   191→    const existing = execRows.length > 0
   192→      ? (execRows[0].outputArtifacts as unknown[]) ?? []
   193→      : [];
   194→
   195→    const updatedArtifacts = [...existing, gateResult];
   196→
   197→    // Mark gate step completed
   198→    await this.db
   199→      .update(executionSteps)
   200→      .set({ status: 'completed', completedAt: new Date() })
   201→      .where(eq(executionSteps.id, gateStepId));
   202→
   203→    // Resume execution — the executor poll loop will continue from here
   204→    await this.db
   205→      .update(pipelineExecutions)
   206→      .set({
   207→        status: 'running',
   208→        outputArtifacts: updatedArtifacts as unknown as Record<string, unknown>[],
   209→      })
   210→      .where(eq(pipelineExecutions.id, executionId));
   211→  }
   212→}
