    69→  const db = {
    70→    _insertedDecisions: insertedDecisions,
    71→    get _updatedExecutionSteps() {
    72→      // pauseAtGate: first update call is executionSteps
    73→      return allUpdates.filter((_, i) => i % 2 === 0);
    74→    },
    75→    get _updatedExecutions() {
    76→      // pauseAtGate: second update call is pipelineExecutions
    77→      return allUpdates.filter((_, i) => i % 2 === 1);
