    82→        insertedDecisions.push(...arr);
    83→        return Promise.resolve();
    84→      }),
    85→    }),
    86→    update: vi.fn().mockImplementation(() => ({
    87→      set: vi.fn().mockImplementation((data: Record<string, unknown>) => ({
    88→        where: vi.fn().mockImplementation(() => {
    89→          allUpdates.push(data);
    90→          return Promise.resolve();
    91→        }),
    92→      })),
    93→    })),
    94→    select: vi.fn(),
    95→  };
    96→
    97→  return db;
    98→}
