    expect(execUpdate).toBeUndefined();

    // The decision update should include feedback
    const decisionUpdate = (db._updatedRows as Record<string, unknown>[]).find(
      (r) => r['status'] === 'rejected',
    );
    expect(decisionUpdate).toBeDefined();
  });

